//  Side effect: mutates the caller's object
function applyDiscount(order, pct) {
  order.total = order.total * (1 - pct); // modifies the ORIGINAL object
  return order;
}

const myOrder = { id: 1, total: 100 };
applyDiscount(myOrder, 0.1);
console.log(myOrder.total); // 90 — caller's object was silently changed!

//  No side effect: return a new object, leave the original intact
function applyDiscountPure(order, pct) {
  return { ...order, total: order.total * (1 - pct) };
}

const original = { id: 1, total: 100 };
const discounted = applyDiscountPure(original, 0.1);
console.log(original.total);    // 100 — unchanged 
console.log(discounted.total);  // 90  — new object

