const user = { name: 'Alice', address: { city: 'Berlin' } };
const userCopy = { ...user }; // shallow copy

userCopy.name = 'Bob';         //  only changes the copy's 'name'
userCopy.address.city = 'Paris'; //  mutates the ORIGINAL nested object!

console.log(user.name);         // 'Alice' 
console.log(user.address.city); // 'Paris'  — unexpected side effect!

// Fix: deep clone
const deepCopy = structuredClone(user);
deepCopy.address.city = 'Tokyo';
console.log(user.address.city); // 'Paris' — original safe
